import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'



class GetUser extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, usersResult: [], selectedValue: ""
        };
    }

    handleSelectChange = (selectedOptions) => {

        this.setState({screen: 0})
        this.setState({selectedValue: selectedOptions.value})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `getVoalteUsers?name=` + selectedOptions.value, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({usersResult: response})

            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });



      }




      componentDidMount() {


        this.callVoalte("Providers Adult")




      }


      callVoalte = (name) => {
        this.setState({screen: 0})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `voalte?name="+ name +"`, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({results: response})

            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });

      }





          render() {


            var header = "Loading ..."







            if (this.state.screen === 1) {
              header = ""
              var content = []

/*
              const roleOption = []


              this.state.results.map(rec => {
                roleOption.push({value: rec.name, label: rec.name})
              })

              console.log(this.state.selectedValue)

              content.push(<div style={{marginTop: "5px", display: "block"}}><Select
              value={this.state.selectedValue}
              name="role"
              options={roleOption}
              className="basic-multi-select"
              classNamePrefix="select"
              onChange={this.handleSelectChange}
            /></div>)


              var tableContent = []

              if (this.state.selectedValue.length > 0) {

                tableContent.push(<tr><td colspan="3">Role: {this.state.selectedValue}</td></tr>)
              }
              this.state.usersResult.map(rec => {
                  console.log(rec)
                  tableContent.push(<tr><td style={{border: "1px solid", padding: "5px"}}>{rec.first_name}</td><td style={{border: "1px solid", padding: "5px"}}>{rec.last_name}</td><td style={{border: "1px solid", padding: "5px"}}>{rec.email_address}</td></tr>)
              })

         */




              //console.log(this.state.results)

            var tableContentformat = []

            this.state.results.map(rec =>
                {
                    content.push(<div><h2>{rec.building}</h2><hr></hr></div>)

                    var tableContent = []

                    rec.unit.map(rec2 => {
                        //content.push(<div style={{marginTop: "20px"}}><h3>&nbsp;&nbsp;&nbsp;&nbsp;-- {rec2.unit}</h3></div>)

                        rec2.users.map(rec3 => {
                            tableContent.push(<tr><td style={{border: "1px solid", padding: "5px"}}>{rec2.unit}</td><td style={{border: "1px solid", padding: "5px"}}>{rec3.last_name}</td><td style={{border: "1px solid", padding: "5px"}}>{rec3.first_name}</td><td style={{border: "1px solid", padding: "5px"}}>{rec3.email_address}</td><td style={{border: "1px solid", padding: "5px"}}>{rec3.role_name}</td></tr>)
                        })


                    })



                    if (tableContent.length > 0) {

                      tableContentformat.push(<tr><td style={{border: "1px solid", padding: "5px"}}><b>Role/Unit</b></td><td style={{border: "1px solid", padding: "5px"}}><button
                      type="button"
                      >
                      Last Name
                    </button>
                    </td><td style={{border: "1px solid", padding: "5px"}}><b>First Name</b></td><td style={{border: "1px solid", padding: "5px"}}><b>Email</b></td><td style={{border: "1px solid", padding: "5px"}}><b>Role Name</b></td></tr>)

                      tableContent.map(rec4 => {
                          tableContentformat.push(rec4)
                      })

                  }



                })



                content.push(<table style={{marginTop: "5px"}}>{tableContentformat}</table>)

          }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default GetUser
